{
  "name": "StreamNexus",
  "description": "A metadata-driven media aggregation platform integrating TMDB, AniList, and VidSrc for a seamless discovery and embed streaming experience."
}

export type MediaType = 'movie' | 'tv' | 'anime' | 'manga';

export interface MediaItem {
  id: string | number;
  tmdbId?: number;
  imdbId?: string;
  anilistId?: number;
  title: string;
  poster: string;
  banner?: string;
  description: string;
  rating: number;
  releaseDate: string;
  type: MediaType;
  genres: string[];
  status?: string;
  // TV/Anime specific
  seasons?: number;
  episodes?: number;
  // Manga specific
  chapters?: number;
}

export interface SeasonInfo {
  season_number: number;
  episode_count: number;
  name: string;
}

export interface EpisodeInfo {
  episode_number: number;
  name: string;
  still_path?: string;
}

// State for the player/reader
export interface PlaybackState {
  isPlaying: boolean;
  season: number;
  episode: number;
  chapter: number;
  isDub: boolean; // 0 = sub, 1 = dub
}

export interface SearchFilters {
  query: string;
  type: MediaType | 'all';
}

export const TMDB_BASE_URL = 'https://api.themoviedb.org/3';
export const TMDB_IMAGE_BASE = 'https://image.tmdb.org/t/p/w500';
export const TMDB_BACKDROP_BASE = 'https://image.tmdb.org/t/p/original';

export const ANILIST_API_URL = 'https://graphql.anilist.co';

export const VIDSRC_BASE = 'https://vidsrc.icu/embed';

// NOTE: In a real production app, keys should be on the server. 
// For this client-side demo, we rely on the user inputting a key or using a demo key if available.
export const STORAGE_KEYS = {
  TMDB_API_KEY: 'sn_tmdb_key',
  WATCH_HISTORY: 'sn_history'
};

import { TMDB_BASE_URL, TMDB_IMAGE_BASE, TMDB_BACKDROP_BASE } from '../constants';
import { MediaItem } from '../types';

const getApiKey = () => localStorage.getItem('sn_tmdb_key') || '';

const fetchTMDB = async (endpoint: string, params: Record<string, string> = {}) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key Missing");

  const query = new URLSearchParams({ api_key: apiKey, ...params }).toString();
  const res = await fetch(`${TMDB_BASE_URL}${endpoint}?${query}`);
  if (!res.ok) throw new Error(`TMDB Error: ${res.statusText}`);
  return res.json();
};

const mapTMDBToMedia = (item: any, type: 'movie' | 'tv'): MediaItem => ({
  id: item.id,
  tmdbId: item.id,
  title: item.title || item.name,
  poster: item.poster_path ? `${TMDB_IMAGE_BASE}${item.poster_path}` : 'https://picsum.photos/300/450',
  banner: item.backdrop_path ? `${TMDB_BACKDROP_BASE}${item.backdrop_path}` : undefined,
  description: item.overview,
  rating: item.vote_average,
  releaseDate: item.release_date || item.first_air_date || 'N/A',
  type,
  genres: [], // Populated in details
  status: 'Released'
});

export const tmdbService = {
  getTrending: async (type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    try {
      const data = await fetchTMDB(`/trending/${type}/week`);
      return data.results.map((i: any) => mapTMDBToMedia(i, type));
    } catch (e) {
      console.error(e);
      return [];
    }
  },

  getDetails: async (id: number, type: 'movie' | 'tv'): Promise<MediaItem | null> => {
    try {
      const data = await fetchTMDB(`/${type}/${id}`, { append_to_response: 'external_ids' });
      const base = mapTMDBToMedia(data, type);
      return {
        ...base,
        imdbId: data.external_ids?.imdb_id,
        genres: data.genres?.map((g: any) => g.name) || [],
        seasons: type === 'tv' ? data.number_of_seasons : undefined,
        episodes: type === 'tv' ? data.number_of_episodes : undefined,
        status: data.status
      };
    } catch (e) {
      console.error(e);
      return null;
    }
  },

  getSeasonDetails: async (id: number, seasonNumber: number) => {
    try {
      return await fetchTMDB(`/tv/${id}/season/${seasonNumber}`);
    } catch (e) {
      return null;
    }
  },

  search: async (query: string, type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    try {
      const data = await fetchTMDB(`/search/${type}`, { query });
      return data.results.map((i: any) => mapTMDBToMedia(i, type));
    } catch (e) {
      return [];
    }
  }
};

import { ANILIST_API_URL } from '../constants';
import { MediaItem } from '../types';

const graphQLRequest = async (query: string, variables: any = {}) => {
  const res = await fetch(ANILIST_API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    },
    body: JSON.stringify({ query, variables }),
  });
  if (!res.ok) throw new Error("AniList Request Failed");
  return res.json();
};

const mapAniListToMedia = (item: any, type: 'anime' | 'manga'): MediaItem => ({
  id: item.id,
  anilistId: item.id,
  title: item.title.english || item.title.romaji,
  poster: item.coverImage.large,
  banner: item.bannerImage,
  description: item.description?.replace(/<[^>]*>?/gm, '') || '', // Strip HTML
  rating: item.averageScore / 10,
  releaseDate: `${item.startDate.year || '?'}-${item.startDate.month || '?'}-${item.startDate.day || '?'}`,
  type,
  genres: item.genres || [],
  status: item.status,
  episodes: item.episodes,
  chapters: item.chapters
});

const MEDIA_QUERY = `
  query ($id: Int, $search: String, $type: MediaType, $sort: [MediaSort]) {
    Page(page: 1, perPage: 20) {
      media(id: $id, search: $search, type: $type, sort: $sort) {
        id
        title {
          romaji
          english
        }
        coverImage {
          large
        }
        bannerImage
        description
        averageScore
        startDate {
          year
          month
          day
        }
        genres
        status
        episodes
        chapters
      }
    }
  }
`;

export const anilistService = {
  getTrending: async (type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      type: type.toUpperCase(),
      sort: ['TRENDING_DESC', 'POPULARITY_DESC']
    });
    return data.data.Page.media.map((i: any) => mapAniListToMedia(i, type));
  },

  getDetails: async (id: number, type: 'anime' | 'manga'): Promise<MediaItem | null> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      id,
      type: type.toUpperCase()
    });
    const item = data.data.Page.media[0];
    return item ? mapAniListToMedia(item, type) : null;
  },

  search: async (query: string, type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      search: query,
      type: type.toUpperCase(),
      sort: ['POPULARITY_DESC']
    });
    return data.data.Page.media.map((i: any) => mapAniListToMedia(i, type));
  }
};

import { VIDSRC_BASE } from '../constants';
import { MediaItem, PlaybackState } from '../types';

export const generateEmbedUrl = (media: MediaItem, state: PlaybackState): string => {
  const { type, tmdbId, imdbId, anilistId } = media;
  const { season, episode, chapter, isDub } = state;

  switch (type) {
    case 'movie':
      // Movie Rule: Use IMDb if exists, else TMDB
      const movieId = imdbId || tmdbId;
      if (!movieId) return '';
      return `${VIDSRC_BASE}/movie/${movieId}`;

    case 'tv':
      // TV Rule: Use IMDb if exists, else TMDB
      // Optional Season/Episode
      const tvId = imdbId || tmdbId;
      if (!tvId) return '';
      if (season && episode) {
        return `${VIDSRC_BASE}/tv/${tvId}/${season}/${episode}`;
      }
      return `${VIDSRC_BASE}/tv/${tvId}`;

    case 'anime':
      // Anime Rule: AniList ID Required. Episode Required. Dub Optional.
      if (!anilistId) return '';
      // Default to episode 1 if not selected, though UI should enforce
      const ep = episode || 1;
      const dubParam = isDub ? '1' : '0';
      return `${VIDSRC_BASE}/anime/${anilistId}/${ep}/${dubParam}`;

    case 'manga':
      // Manga Rule: AniList ID Required. Chapter Required.
      if (!anilistId) return '';
      const chap = chapter || 1;
      return `${VIDSRC_BASE}/manga/${anilistId}/${chap}`;

    default:
      return '';
  }
};

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, MonitorPlay, Settings, Menu, X } from 'lucide-react';
import { STORAGE_KEYS } from '../constants';

const Navbar: React.FC = () => {
  const [query, setQuery] = useState('');
  const [showSettings, setShowSettings] = useState(false);
  const [apiKey, setApiKey] = useState(localStorage.getItem(STORAGE_KEYS.TMDB_API_KEY) || '');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const navigate = useNavigate();

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      navigate(`/search?q=${encodeURIComponent(query)}`);
      setMobileMenuOpen(false);
    }
  };

  const saveKey = () => {
    localStorage.setItem(STORAGE_KEYS.TMDB_API_KEY, apiKey);
    setShowSettings(false);
    window.location.reload(); // Reload to pick up new key in services
  };

  return (
    <nav className="fixed top-0 w-full z-50 bg-nexus-900/95 border-b border-nexus-700 backdrop-blur-md">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2 text-nexus-accent hover:text-red-500 transition-colors">
          <MonitorPlay size={28} />
          <span className="text-xl font-bold tracking-tight text-white hidden sm:block">StreamNexus</span>
        </Link>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center gap-6 text-sm font-medium text-gray-300">
          <Link to="/?cat=movie" className="hover:text-white transition">Movies</Link>
          <Link to="/?cat=tv" className="hover:text-white transition">TV Shows</Link>
          <Link to="/?cat=anime" className="hover:text-white transition">Anime</Link>
          <Link to="/?cat=manga" className="hover:text-white transition">Manga</Link>
        </div>

        {/* Search & Settings */}
        <div className="flex items-center gap-4">
          <form onSubmit={handleSearch} className="relative hidden sm:block">
            <input
              type="text"
              placeholder="Search..."
              className="bg-nexus-800 text-sm text-white px-4 py-1.5 pl-9 rounded-full border border-nexus-700 focus:border-nexus-accent focus:outline-none w-48 focus:w-64 transition-all"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          </form>

          <button onClick={() => setShowSettings(!showSettings)} className="text-gray-400 hover:text-white">
            <Settings size={20} />
          </button>

          {/* Mobile Menu Toggle */}
          <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="md:hidden text-gray-400">
            {mobileMenuOpen ? <X /> : <Menu />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="md:hidden bg-nexus-800 border-b border-nexus-700 p-4 space-y-4">
           <form onSubmit={handleSearch} className="relative">
            <input
              type="text"
              placeholder="Search..."
              className="bg-nexus-900 text-sm text-white px-4 py-2 w-full rounded-md border border-nexus-700"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
          </form>
          <div className="flex flex-col gap-2 text-gray-300">
            <Link to="/?cat=movie" onClick={() => setMobileMenuOpen(false)}>Movies</Link>
            <Link to="/?cat=tv" onClick={() => setMobileMenuOpen(false)}>TV Shows</Link>
            <Link to="/?cat=anime" onClick={() => setMobileMenuOpen(false)}>Anime</Link>
            <Link to="/?cat=manga" onClick={() => setMobileMenuOpen(false)}>Manga</Link>
          </div>
        </div>
      )}

      {/* API Key Modal */}
      {showSettings && (
        <div className="absolute top-16 right-4 w-72 bg-nexus-800 border border-nexus-700 rounded-lg p-4 shadow-xl z-50">
          <h3 className="text-white font-bold mb-2">Configuration</h3>
          <div className="space-y-3">
            <div>
              <label className="text-xs text-gray-400 block mb-1">TMDB API Key (Required for Movies/TV)</label>
              <input 
                type="text" 
                value={apiKey} 
                onChange={(e) => setApiKey(e.target.value)}
                className="w-full bg-nexus-900 border border-nexus-700 rounded px-2 py-1 text-xs text-white"
                placeholder="Enter TMDB Key"
              />
            </div>
            <button 
              onClick={saveKey}
              className="w-full bg-nexus-accent hover:bg-red-700 text-white py-1 rounded text-sm font-semibold transition"
            >
              Save & Reload
            </button>
            <p className="text-[10px] text-gray-500 mt-2">
              Keys are stored in your browser's LocalStorage only.
            </p>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

