import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { tmdbService } from '../services/tmdb';
import { anilistService } from '../services/anilist';
import { MediaItem } from '../types';
import MediaCard from '../components/MediaCard';
import { Loader2, AlertCircle } from 'lucide-react';
import { STORAGE_KEYS } from '../constants';

const Home: React.FC = () => {
  const [items, setItems] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchParams] = useSearchParams();

  const category = searchParams.get('cat') || 'movie';

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError('');
      try {
        let results: MediaItem[] = [];

        if (category === 'movie' || category === 'tv') {
            const hasKey = localStorage.getItem(STORAGE_KEYS.TMDB_API_KEY);
            if (!hasKey) {
                setError("Please enter a TMDB API Key in Settings (top right gear icon) to view Movies & TV.");
                setLoading(false);
                return;
            }
            results = await tmdbService.getTrending(category);
        } else if (category === 'anime' || category === 'manga') {
            results = await anilistService.getTrending(category);
        }

        setItems(results);
      } catch (err) {
        setError("Failed to load content. Check your API key or connection.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [category]);

  return (
    <div className="container mx-auto px-4 py-8 mt-16">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2 capitalize">
          Trending {category === 'tv' ? 'TV Shows' : category === 'movie' ? 'Movies' : category}
        </h1>
        <p className="text-gray-400">Discover the most popular content this week.</p>
      </header>

      {loading ? (
        <div className="flex justify-center items-center h-64">
          <Loader2 className="animate-spin text-nexus-accent" size={48} />
        </div>
      ) : error ? (
        <div className="bg-red-900/20 border border-red-800 p-6 rounded-lg text-center">
            <AlertCircle className="mx-auto text-red-500 mb-2" size={32} />
            <h3 className="text-xl font-bold text-white mb-2">Error Loading Data</h3>
            <p className="text-gray-300">{error}</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
          {items.map((item) => (
            <MediaCard key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  );
};

export default Home;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useLocation } from 'react-router-dom';
import { MediaItem, PlaybackState, SeasonInfo } from '../types';
import { tmdbService } from '../services/tmdb';
import { anilistService } from '../services/anilist';
import { generateEmbedUrl } from '../services/embed';
import { Play, Calendar, Star, Layers, BookOpen, ChevronDown } from 'lucide-react';

const Details: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  // Determine type from URL path: /movie/123 -> type = movie
  const type = location.pathname.split('/')[1] as 'movie' | 'tv' | 'anime' | 'manga';

  const [media, setMedia] = useState<MediaItem | null>(null);
  const [loading, setLoading] = useState(true);
  const playerRef = useRef<HTMLDivElement>(null);

  // Playback State
  const [playState, setPlayState] = useState<PlaybackState>({
    isPlaying: false,
    season: 1,
    episode: 1,
    chapter: 1,
    isDub: false
  });

  // Aux state for TV seasons
  const [seasonsData, setSeasonsData] = useState<SeasonInfo[]>([]);
  const [episodesInSeason, setEpisodesInSeason] = useState<number>(0);

  useEffect(() => {
    const fetchDetails = async () => {
      if (!id) return;
      setLoading(true);
      try {
        let result: MediaItem | null = null;
        if (type === 'movie' || type === 'tv') {
          result = await tmdbService.getDetails(Number(id), type);
          if (type === 'tv' && result) {
            // Rough logic: TMDB seasons often start at 1, sometimes 0 (Specials). 
            // For this simplified demo, we assume regular numbering.
            setEpisodesInSeason(result.episodes || 0); // Total ep fallback
            // In a real app, we'd fetch specific season details to get episode counts per season
            // Here we just use a generic count or rely on user to pick.
          }
        } else {
          result = await anilistService.getDetails(Number(id), type);
        }
        setMedia(result);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchDetails();

    // Reset Playback state on new media load
    setPlayState({
      isPlaying: false,
      season: 1,
      episode: 1,
      chapter: 1,
      isDub: false
    });
  }, [id, type]);

  const handleWatch = () => {
    setPlayState(prev => ({ ...prev, isPlaying: true }));
    setTimeout(() => {
      playerRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const renderEmbed = () => {
    if (!media) return null;
    const url = generateEmbedUrl(media, playState);

    return (
      <div className="w-full h-full bg-black rounded-lg overflow-hidden relative group">
         <iframe
          src={url}
          className="w-full h-full border-0"
          allowFullScreen
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          referrerPolicy="origin"
        />
        {/* Overlay info for demo clarity */}
        <div className="absolute top-2 left-2 bg-black/50 text-[10px] text-gray-500 px-2 rounded opacity-0 group-hover:opacity-100 transition pointer-events-none">
            Src: {url}
        </div>
      </div>
    );
  };

  if (loading) return <div className="h-screen flex items-center justify-center text-white">Loading Metadata...</div>;
  if (!media) return <div className="h-screen flex items-center justify-center text-white">Media Not Found</div>;

  return (
    <div className="min-h-screen pb-20 mt-16">
      {/* Hero Banner */}
      <div className="relative h-[50vh] md:h-[70vh] w-full">
        <div className="absolute inset-0">
          <img 
            src={media.banner || media.poster} 
            alt="Banner" 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-nexus-900 via-nexus-900/60 to-transparent" />
        </div>

        <div className="absolute bottom-0 left-0 w-full p-6 md:p-12">
          <div className="container mx-auto flex flex-col md:flex-row gap-8 items-end">
            {/* Poster */}
            <img 
              src={media.poster} 
              alt={media.title} 
              className="w-32 md:w-48 rounded-lg shadow-2xl border border-white/10 hidden sm:block"
            />

            {/* Info */}
            <div className="flex-1 space-y-4 text-shadow-md">
              <h1 className="text-3xl md:text-5xl font-bold text-white">{media.title}</h1>

              <div className="flex flex-wrap items-center gap-4 text-sm md:text-base text-gray-200">
                <span className="flex items-center gap-1 text-yellow-400 font-bold">
                  <Star size={16} fill="currentColor" /> {media.rating.toFixed(1)}
                </span>
                <span className="flex items-center gap-1">
                  <Calendar size={16} /> {media.releaseDate.split('-')[0]}
                </span>
                <span className="px-2 py-0.5 bg-white/20 rounded text-xs uppercase tracking-wide">
                  {media.type}
                </span>
                {media.status && <span className="text-green-400">{media.status}</span>}
              </div>

              <p className="text-gray-300 max-w-2xl line-clamp-3 md:line-clamp-none">
                {media.description}
              </p>

              <div className="flex gap-2 pt-4">
                 {media.genres.map(g => (
                    <span key={g} className="text-xs bg-nexus-800 border border-nexus-700 px-2 py-1 rounded-full text-gray-300">
                        {g}
                    </span>
                 ))}
              </div>

              <button 
                onClick={handleWatch}
                className="mt-6 bg-nexus-accent hover:bg-nexus-accentHover text-white px-8 py-3 rounded-full font-bold flex items-center gap-2 transition-transform active:scale-95"
              >
                {media.type === 'manga' ? <BookOpen size={20} /> : <Play size={20} fill="currentColor" />}
                {media.type === 'manga' ? 'Start Reading' : 'Watch Now'}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Control Panel for Series/Manga */}
      {playState.isPlaying && (
