import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { tmdbService } from '../services/tmdb';
import { anilistService } from '../services/anilist';
import { MediaItem } from '../types';
import MediaCard from '../components/MediaCard';
import { Loader2 } from 'lucide-react';
import { STORAGE_KEYS } from '../constants';

const SearchPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q') || '';
  const [results, setResults] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const performSearch = async () => {
      if (!query) return;
      setLoading(true);

      try {
        const promises = [];

        // TMDB Search (Check Key)
        if (localStorage.getItem(STORAGE_KEYS.TMDB_API_KEY)) {
            promises.push(tmdbService.search(query, 'movie'));
            promises.push(tmdbService.search(query, 'tv'));
        }

        // AniList Search
        promises.push(anilistService.search(query, 'anime'));
        promises.push(anilistService.search(query, 'manga'));

        const responseGroups = await Promise.all(promises);
        const flatResults = responseGroups.flat();

        // Simple sort by rating or relevance (here just flattened)
        setResults(flatResults);
      } catch (e) {
        console.error("Search error", e);
      } finally {
        setLoading(false);
      }
    };

    const debounce = setTimeout(performSearch, 500);
    return () => clearTimeout(debounce);
  }, [query]);

  return (
    <div className="container mx-auto px-4 py-8 mt-16">
      <h2 className="text-2xl font-bold text-white mb-6">
        Results for "{query}"
      </h2>

      {loading ? (
        <div className="flex justify-center py-12">
            <Loader2 className="animate-spin text-nexus-accent" size={32} />
        </div>
      ) : results.length > 0 ? (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
            {results.map((item, idx) => (
                <MediaCard key={`${item.type}-${item.id}-${idx}`} item={item} />
            ))}
        </div>
      ) : (
        <div className="text-center text-gray-500 py-12">
            No results found. (Did you add a TMDB API key?)
        </div>
      )}
    </div>
  );
};

