    topRatedMovies: [],
    popularTv: [],
    actionMovies: [],
    scifiMovies: [],
    dramaMovies: []
  });

  const navigate = useNavigate();

  useEffect(() => {
    const fetchContent = async () => {
      setLoading(true);
      try {
        // Parallel fetching for performance
        const [
          trendingM, 
          trendingT, 
          topRatedM, 
          popularT,
          action,
          scifi,
          drama
        ] = await Promise.all([
          tmdbService.getTrending('movie'),
          tmdbService.getTrending('tv'),
          tmdbService.getTopRated('movie'),
          tmdbService.getPopular('tv'),
