import { VIDSRC_BASE } from '../constants';
import { MediaItem, PlaybackState } from '../types';

export const generateEmbedUrl = (media: MediaItem, state: PlaybackState): string => {
  const { type, tmdbId, anilistId } = media;
  const { season, episode, chapter, isDub } = state;

  // STRICT RULE: Use TMDB ID for Movies and TV. Do not assume or guess IMDb IDs.
  // The system relies on the numeric TMDB ID returned by the API.

  switch (type) {
    case 'movie':
      if (!tmdbId) return '';
      // Direct TMDB ID usage - No 'tt' prefix, no IMDb guessing
      return `${VIDSRC_BASE}/movie/${tmdbId}`;

    case 'tv':
      if (!tmdbId) return '';
      // Direct TMDB ID usage
      if (season && episode) {
        return `${VIDSRC_BASE}/tv/${tmdbId}/${season}/${episode}`;
      }
      return `${VIDSRC_BASE}/tv/${tmdbId}`;

    case 'anime':
      if (!anilistId) return '';
      const ep = episode || 1;
      const dubParam = isDub ? '1' : '0';
      return `${VIDSRC_BASE}/anime/${anilistId}/${ep}/${dubParam}`;

    case 'manga':
      if (!anilistId) return '';
      const chap = chapter || 1;
      return `${VIDSRC_BASE}/manga/${anilistId}/${chap}`;

    default:
      return '';
  }
};

