import { VIDSRC_BASE, VIDSRC_RU_BASE } from '../constants';
import { MediaItem, PlaybackState } from '../types';

export const generateEmbedUrl = (media: MediaItem, state: PlaybackState): string => {
  const { type, tmdbId, anilistId } = media;
  const { season, episode, chapter, isDub, server } = state;

  // STRICT RULE: Use TMDB ID for Movies and TV.
  // Server 1: vidsrc.icu
  // Server 2: vidsrc-embed.ru

  switch (type) {
    case 'movie':
      if (!tmdbId) return '';
      // Server 2 Logic
      if (server === 2) {
        return `${VIDSRC_RU_BASE}/movie/${tmdbId}`;
      }
      // Server 1 Logic (Default)
      return `${VIDSRC_BASE}/movie/${tmdbId}`;

    case 'tv':
      if (!tmdbId) return '';

      if (server === 2) {
        // Server 2 uses hyphen separator for seasons/episodes
        if (season && episode) {
          return `${VIDSRC_RU_BASE}/tv/${tmdbId}/${season}-${episode}`;
        }
        return `${VIDSRC_RU_BASE}/tv/${tmdbId}`;
      }

      // Server 1 (Default) uses slash separator
      if (season && episode) {
        return `${VIDSRC_BASE}/tv/${tmdbId}/${season}/${episode}`;
      }
      return `${VIDSRC_BASE}/tv/${tmdbId}`;

    case 'anime':
      // Anime is not affected by server selection, strictly uses VidSrc ICU logic
      if (!anilistId) return '';
      const ep = episode || 1;
      const dubParam = isDub ? '1' : '0';
      return `${VIDSRC_BASE}/anime/${anilistId}/${ep}/${dubParam}`;

    case 'manga':
      // Manga is not affected by server selection
      if (!anilistId) return '';
      const chap = chapter || 1;
      return `${VIDSRC_BASE}/manga/${anilistId}/${chap}`;

    default:
      return '';
  }
};

