  tmdbId?: number;
  imdbId?: string;
  anilistId?: number;
  title: string;
  poster: string;
  banner?: string;
  description: string;
  rating: number;
  releaseDate: string;
  type: MediaType;
  genres: string[];
  status?: string;
  // TV specific
  seasons?: number; // Total number of seasons
  episodes?: number; // Total episodes (or per season count in some contexts)
  // Anime/Manga specific
  nextAiringEpisode?: number;
  // Collection specific (Movies)
  collectionId?: number;
  collectionName?: string;
  // Manga specific
  chapters?: number;
}

export interface SeasonInfo {
  id: number;
  name: string;
  season_number: number;
  episode_count: number;
  air_date: string;
  poster_path?: string;
}

export interface EpisodeInfo {
  id: number;
  episode_number: number;
  name: string;
  overview: string;
  still_path?: string;
  air_date: string;
}

// State for the player/reader
export interface PlaybackState {
  isPlaying: boolean;
  season: number;
  episode: number;
  chapter: number;
  isDub: boolean; // 0 = sub, 1 = dub
  server: 1 | 2; // 1 = VidSrc ICU, 2 = VidSrc Embed RU
}

export interface SearchFilters {
  query: string;
  type: MediaType | 'all';
}

import { ANILIST_API_URL, ANILIST_TOKEN } from '../constants';
import { MediaItem } from '../types';

const graphQLRequest = async (query: string, variables: any = {}) => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  if (ANILIST_TOKEN) {
    headers['Authorization'] = `Bearer ${ANILIST_TOKEN}`;
  }

  const res = await fetch(ANILIST_API_URL, {
    method: 'POST',
    headers,
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    console.warn("AniList Request Warning", res.status);
    // Try to return json even on error to see messages, or throw
    try { return await res.json(); } catch(e) { throw new Error("AniList Failed"); }
  }
  return res.json();
};

const mapAniListToMedia = (item: any, type: 'anime' | 'manga'): MediaItem => ({
  id: item.id,
  anilistId: item.id,
  title: item.title.english || item.title.romaji,
  poster: item.coverImage.large,
  banner: item.bannerImage,
  description: item.description?.replace(/<[^>]*>?/gm, '') || '', // Strip HTML
  rating: item.averageScore ? item.averageScore / 10 : 0,
  releaseDate: item.startDate.year ? `${item.startDate.year}-${item.startDate.month || '01'}-${item.startDate.day || '01'}` : 'N/A',
  type,
  genres: item.genres || [],
  status: item.status,
  episodes: item.episodes || 0, // Total episodes
  chapters: item.chapters || 0, // Total chapters
});

const MEDIA_QUERY = `
  query ($id: Int, $search: String, $type: MediaType, $sort: [MediaSort]) {
    Page(page: 1, perPage: 20) {
      media(id: $id, search: $search, type: $type, sort: $sort) {
        id
        title {
          romaji
          english
        }
        coverImage {
          large
        }
        bannerImage
        description
        averageScore
        startDate {
          year
          month
          day
        }
        genres
        status
        episodes
        chapters
      }
    }
  }
`;

export const anilistService = {
  getTrending: async (type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      type: type.toUpperCase(),
      sort: ['TRENDING_DESC', 'POPULARITY_DESC']
    });
    return data.data?.Page?.media?.map((i: any) => mapAniListToMedia(i, type)) || [];
  },

  getDetails: async (id: number, type: 'anime' | 'manga'): Promise<MediaItem | null> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      id,
      type: type.toUpperCase()
    });
    const item = data.data?.Page?.media?.[0];
    return item ? mapAniListToMedia(item, type) : null;
  },

  search: async (query: string, type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      search: query,
      type: type.toUpperCase(),
      sort: ['POPULARITY_DESC']
    });
    return data.data?.Page?.media?.map((i: any) => mapAniListToMedia(i, type)) || [];
  }
};

import { TMDB_BASE_URL, TMDB_IMAGE_BASE, TMDB_BACKDROP_BASE, DEFAULT_TMDB_API_KEY } from '../constants';
import { MediaItem, EpisodeInfo, SeasonInfo } from '../types';

// Strictly use the default key (server-side simulation)
const apiKey = DEFAULT_TMDB_API_KEY;

const fetchTMDB = async (endpoint: string, params: Record<string, string> = {}) => {
  if (!apiKey) return { results: [] }; 

  const query = new URLSearchParams({ api_key: apiKey, ...params }).toString();
  try {
    const res = await fetch(`${TMDB_BASE_URL}${endpoint}?${query}`);
    if (!res.ok) {
        console.warn(`TMDB Fetch Error: ${res.status} ${res.statusText}`);
        return {}; 
    }
    return res.json();
  } catch (error) {
    console.error("Network error:", error);
    return {};
  }
};

const mapTMDBToMedia = (item: any, type: 'movie' | 'tv'): MediaItem => ({
  id: item.id,
  tmdbId: item.id,
  title: item.title || item.name,
  poster: item.poster_path ? `${TMDB_IMAGE_BASE}${item.poster_path}` : 'https://picsum.photos/300/450?grayscale',
  banner: item.backdrop_path ? `${TMDB_BACKDROP_BASE}${item.backdrop_path}` : undefined,
  description: item.overview,
  rating: item.vote_average,
  releaseDate: item.release_date || item.first_air_date || 'N/A',
  type,
  genres: [], // Populated in details
  status: 'Released'
});

export const tmdbService = {
  getTrending: async (type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    const data = await fetchTMDB(`/trending/${type}/day`);
    return (data.results || []).map((i: any) => mapTMDBToMedia(i, type));
  },

  getPopular: async (type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    const data = await fetchTMDB(`/${type}/popular`);
    return (data.results || []).map((i: any) => mapTMDBToMedia(i, type));
  },

  getTopRated: async (type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    const data = await fetchTMDB(`/${type}/top_rated`);
    return (data.results || []).map((i: any) => mapTMDBToMedia(i, type));
  },

  getByGenre: async (type: 'movie' | 'tv', genreId: number): Promise<MediaItem[]> => {
    const data = await fetchTMDB(`/discover/${type}`, { 
        with_genres: genreId.toString(),
        sort_by: 'popularity.desc'
    });
    return (data.results || []).map((i: any) => mapTMDBToMedia(i, type));
  },

  getDetails: async (id: number, type: 'movie' | 'tv'): Promise<MediaItem | null> => {
    try {
      const data = await fetchTMDB(`/${type}/${id}`, { append_to_response: 'external_ids,genres' });
      if (!data || !data.id) return null;

      const base = mapTMDBToMedia(data, type);
      return {
        ...base,
        imdbId: data.external_ids?.imdb_id,
        genres: data.genres?.map((g: any) => g.name) || [],
        seasons: type === 'tv' ? data.number_of_seasons : undefined,
        episodes: type === 'tv' ? data.number_of_episodes : undefined,
        status: data.status,
        collectionId: data.belongs_to_collection?.id,
        collectionName: data.belongs_to_collection?.name
      };
    } catch (e) {
      return null;
    }
  },

  getSeason: async (tmdbId: number, seasonNumber: number): Promise<{ info: SeasonInfo, episodes: EpisodeInfo[] }> => {
    try {
      const data = await fetchTMDB(`/tv/${tmdbId}/season/${seasonNumber}`);
      if (!data) return { info: {} as SeasonInfo, episodes: [] };

      const episodes = (data.episodes || []).map((ep: any) => ({
        id: ep.id,
        episode_number: ep.episode_number,
        name: ep.name,
        overview: ep.overview,
        still_path: ep.still_path ? `${TMDB_IMAGE_BASE}${ep.still_path}` : undefined,
        air_date: ep.air_date
      }));

      return { 
          info: {
              id: data.id,
              name: data.name,
              season_number: data.season_number,
              episode_count: episodes.length,
              air_date: data.air_date,
              poster_path: data.poster_path ? `${TMDB_IMAGE_BASE}${data.poster_path}` : undefined
          }, 
          episodes 
      };
    } catch (e) {
      return { info: {} as SeasonInfo, episodes: [] };
    }
  },

  getCollection: async (collectionId: number): Promise<MediaItem[]> => {
      const data = await fetchTMDB(`/collection/${collectionId}`);
      if (!data || !data.parts) return [];

      const sortedParts = data.parts.sort((a: any, b: any) => {
          return new Date(a.release_date).getTime() - new Date(b.release_date).getTime();
      });

      return sortedParts.map((i: any) => mapTMDBToMedia(i, 'movie'));
  },

  search: async (query: string, type: 'movie' | 'tv'): Promise<MediaItem[]> => {
    const data = await fetchTMDB(`/search/${type}`, { query });
    return (data.results || []).map((i: any) => mapTMDBToMedia(i, type));
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { MediaItem, PlaybackState, EpisodeInfo } from '../types';
import { tmdbService } from '../services/tmdb';
import { anilistService } from '../services/anilist';
import { generateEmbedUrl } from '../services/embed';
import Row from '../components/Row';
import { Play, Calendar, Star, BookOpen, MonitorPlay, Server, Layers, Image as ImageIcon } from 'lucide-react';

const Details: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  // Determine type from URL path: /movie/123 -> type = movie
  const type = location.pathname.split('/')[1] as 'movie' | 'tv' | 'anime' | 'manga';

  const [media, setMedia] = useState<MediaItem | null>(null);
  const [collection, setCollection] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(true);
  const playerRef = useRef<HTMLDivElement>(null);

  // TV Specific Data
  const [episodes, setEpisodes] = useState<EpisodeInfo[]>([]);
  const [loadingEpisodes, setLoadingEpisodes] = useState(false);

  // Playback State
  const [playState, setPlayState] = useState<PlaybackState>({
    isPlaying: false,
    season: 1,
    episode: 1,
    chapter: 1,
    isDub: false,
    server: 1
  });

  // Fetch Media Details
  useEffect(() => {
    const fetchDetails = async () => {
      if (!id) return;
      setLoading(true);
      try {
        let result: MediaItem | null = null;
        if (type === 'movie' || type === 'tv') {
          result = await tmdbService.getDetails(Number(id), type);

          // If movie part of collection, fetch collection
          if (type === 'movie' && result?.collectionId) {
             const colParts = await tmdbService.getCollection(result.collectionId);
             setCollection(colParts.filter(p => p.id !== result?.id)); // Remove current
          } else {
             setCollection([]);
          }

        } else {
          result = await anilistService.getDetails(Number(id), type);
        }
        setMedia(result);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchDetails();

    // Reset Playback state on new media load
    setPlayState({
      isPlaying: false,
      season: 1,
      episode: 1,
      chapter: 1,
      isDub: false,
      server: 1
    });
    setEpisodes([]);
  }, [id, type]);

  // Fetch TV Episodes when Season Changes or Media Loads
  useEffect(() => {
    if (type === 'tv' && media?.tmdbId) {
      const fetchEps = async () => {
        setLoadingEpisodes(true);
        const data = await tmdbService.getSeason(media.tmdbId!, playState.season);
        setEpisodes(data.episodes);
        setLoadingEpisodes(false);
      };
      fetchEps();
    }
  }, [type, media?.tmdbId, playState.season]);

  const handleWatch = () => {
    setPlayState(prev => ({ ...prev, isPlaying: true }));
    setTimeout(() => {
      playerRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const selectEpisode = (epNum: number) => {
    setPlayState(prev => ({ ...prev, episode: epNum, isPlaying: true }));
    playerRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const selectChapter = (chapNum: number) => {
      setPlayState(prev => ({ ...prev, chapter: chapNum, isPlaying: true }));
      playerRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const renderEmbed = () => {
    if (!media) return null;
    const url = generateEmbedUrl(media, playState);

    return (
      <div className="w-full h-full bg-black rounded-lg overflow-hidden relative group">
         <iframe
          src={url}
          className="w-full h-full border-0"
          allowFullScreen
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          referrerPolicy="origin"
        />
        <div className="absolute top-2 left-2 bg-black/50 text-[10px] text-gray-500 px-2 rounded opacity-0 group-hover:opacity-100 transition pointer-events-none">
            Src: {url}
        </div>
      </div>
    );
  };

  if (loading) return <div className="h-screen flex items-center justify-center text-white">Loading Metadata...</div>;
  if (!media) return <div className="h-screen flex items-center justify-center text-white">Media Not Found</div>;

  return (
    <div className="min-h-screen pb-20 mt-16">
      {/* Hero Banner */}
      <div className="relative h-[50vh] md:h-[70vh] w-full">
        <div className="absolute inset-0">
          <img 
            src={media.banner || media.poster} 
            alt="Banner" 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-nexus-900 via-nexus-900/60 to-transparent" />
        </div>

        <div className="absolute bottom-0 left-0 w-full p-6 md:p-12">
          <div className="container mx-auto flex flex-col md:flex-row gap-8 items-end">
            <img 
              src={media.poster} 
              alt={media.title} 
              className="w-32 md:w-48 rounded-lg shadow-2xl border border-white/10 hidden sm:block"
            />

            <div className="flex-1 space-y-4 text-shadow-md">
              <h1 className="text-3xl md:text-5xl font-bold text-white">{media.title}</h1>

              <div className="flex flex-wrap items-center gap-4 text-sm md:text-base text-gray-200">
                <span className="flex items-center gap-1 text-yellow-400 font-bold">
                  <Star size={16} fill="currentColor" /> {media.rating.toFixed(1)}
                </span>
                <span className="flex items-center gap-1">
                  <Calendar size={16} /> {media.releaseDate.split('-')[0]}
                </span>
                <span className="px-2 py-0.5 bg-white/20 rounded text-xs uppercase tracking-wide">
                  {media.type}
                </span>
                {media.status && <span className="text-green-400">{media.status}</span>}
              </div>

              <p className="text-gray-300 max-w-2xl line-clamp-3 md:line-clamp-none">
                {media.description}
              </p>

              <button 
                onClick={handleWatch}
                className="mt-6 bg-nexus-accent hover:bg-nexus-accentHover text-white px-8 py-3 rounded-full font-bold flex items-center gap-2 transition-transform active:scale-95"
              >
                {media.type === 'manga' ? <BookOpen size={20} /> : <Play size={20} fill="currentColor" />}
                {media.type === 'manga' ? 'Start Reading' : 'Watch Now'}
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">

        {/* Player Section */}
        {playState.isPlaying && (
            <div ref={playerRef} className="mb-12 animate-fade-in-up">
                 <div className="bg-nexus-800 rounded-t-xl p-4 flex flex-wrap gap-4 items-center justify-between border-b border-nexus-700">
                    <h3 className="font-bold text-white flex items-center gap-2">
                        <MonitorPlay size={20} className="text-nexus-accent" />
                        {media.type === 'manga' ? `Chapter ${playState.chapter}` : 
                         media.type === 'movie' ? 'Watching Movie' :
                         `S${playState.season}:E${playState.episode}`}
                    </h3>

                    {/* Server Toggle for Movies/TV */}
                    {(media.type === 'movie' || media.type === 'tv') && (
                        <div className="flex items-center gap-2 bg-nexus-900 rounded p-1 border border-nexus-700">
                            <span className="text-[10px] text-gray-500 px-2 uppercase font-bold tracking-wider flex items-center gap-1">
                                <Server size={10} /> Server
                            </span>
                            <button
                                onClick={() => setPlayState(p => ({...p, server: 1}))}
                                className={`px-3 py-1 text-xs font-bold rounded transition-colors ${playState.server === 1 ? 'bg-nexus-accent text-white' : 'text-gray-400 hover:text-white'}`}
                            >
                                MAIN
                            </button>
                            <button
                                onClick={() => setPlayState(p => ({...p, server: 2}))}
                                className={`px-3 py-1 text-xs font-bold rounded transition-colors ${playState.server === 2 ? 'bg-nexus-accent text-white' : 'text-gray-400 hover:text-white'}`}
                            >
                                ALT
                            </button>
                        </div>
                    )}
                 </div>

                 <div className="aspect-video w-full bg-black rounded-b-xl overflow-hidden shadow-2xl border border-nexus-700 border-t-0">
                    {renderEmbed()}
                 </div>
            </div>
        )}

        {/* --- TV SHOWS: Seasons & Episodes --- */}
        {type === 'tv' && media.seasons && (
            <div className="space-y-6">
                <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <Layers className="text-nexus-accent" /> Episodes
                    </h2>
                    <select 
                        className="bg-nexus-800 text-white border border-nexus-700 rounded px-4 py-2 outline-none focus:border-nexus-accent"
                        value={playState.season}
                        onChange={(e) => setPlayState(prev => ({ ...prev, season: Number(e.target.value), episode: 1 }))}
                    >
                        {Array.from({ length: media.seasons }, (_, i) => i + 1).map(s => (
                            <option key={s} value={s}>Season {s}</option>
                        ))}
                    </select>
                </div>

                {loadingEpisodes ? (
                    <div className="h-40 flex items-center justify-center text-gray-500">Loading episodes...</div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                        {episodes.map((ep) => (
                            <button 
                                key={ep.id}
                                onClick={() => selectEpisode(ep.episode_number)}
                                className={`flex gap-4 p-3 rounded-lg border text-left transition-all ${
                                    playState.episode === ep.episode_number && playState.isPlaying
                                    ? 'bg-nexus-800 border-nexus-accent' 
                                    : 'bg-nexus-900 border-nexus-800 hover:bg-nexus-800'
                                }`}
                            >
                                <div className="w-24 h-16 flex-shrink-0 bg-black rounded overflow-hidden relative">
                                    {ep.still_path ? (
                                        <img src={ep.still_path} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-gray-700">
                                            <ImageIcon size={20} />
                                        </div>
                                    )}
                                    <div className="absolute bottom-1 right-1 bg-black/80 text-[10px] px-1 rounded text-white">
                                        Ep {ep.episode_number}
                                    </div>
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-sm font-bold text-white truncate">{ep.name}</h4>
                                    <p className="text-xs text-gray-500 mt-1 line-clamp-2">{ep.overview || "No description available."}</p>
                                </div>
                            </button>
                        ))}
                    </div>
                )}
            </div>
        )}

        {/* --- ANIME: Episodes Grid --- */}
        {type === 'anime' && (media.episodes || 0) > 0 && (
            <div className="space-y-6">
                <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <Layers className="text-nexus-accent" /> Episodes
                    </h2>
                    <div className="flex bg-nexus-800 rounded border border-nexus-700 p-1">
                        <button 
                            onClick={() => setPlayState(p => ({...p, isDub: false}))}
                            className={`px-4 py-1.5 text-sm rounded transition-colors ${!playState.isDub ? 'bg-nexus-700 text-white font-bold' : 'text-gray-400 hover:text-white'}`}
                        >
                            Sub
                        </button>
                        <button 
                            onClick={() => setPlayState(p => ({...p, isDub: true}))}
                            className={`px-4 py-1.5 text-sm rounded transition-colors ${playState.isDub ? 'bg-nexus-700 text-white font-bold' : 'text-gray-400 hover:text-white'}`}
                        >
                            Dub
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-12 gap-2">
                    {Array.from({ length: media.episodes || 0 }, (_, i) => i + 1).map(num => (
                        <button
                            key={num}
                            onClick={() => selectEpisode(num)}
                            className={`py-2 rounded font-mono text-sm font-bold border transition-all ${
                                playState.episode === num && playState.isPlaying
                                ? 'bg-nexus-accent border-nexus-accent text-white' 
                                : 'bg-nexus-800 border-nexus-700 text-gray-300 hover:bg-nexus-700 hover:text-white'
                            }`}
                        >
                            {num}
                        </button>
                    ))}
                </div>
            </div>
        )}

        {/* --- MANGA: Chapter Selector --- */}
        {type === 'manga' && (media.chapters || 0) > 0 && (
            <div className="space-y-6">
                 <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                    <BookOpen className="text-nexus-accent" /> Chapters
                </h2>
                <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-12 gap-2">
                    {Array.from({ length: media.chapters || 0 }, (_, i) => i + 1).map(num => (
                        <button
                            key={num}
                            onClick={() => selectChapter(num)}
                            className={`py-2 rounded font-mono text-sm font-bold border transition-all ${
                                playState.chapter === num && playState.isPlaying
                                ? 'bg-nexus-accent border-nexus-accent text-white' 
                                : 'bg-nexus-800 border-nexus-700 text-gray-300 hover:bg-nexus-700 hover:text-white'
                            }`}
                        >
                            {num}
                        </button>
                    ))}
                </div>
            </div>
        )}

        {/* --- MOVIES: Collection --- */}
        {collection.length > 0 && (
             <div className="mt-12">
                <Row title={`More in the ${media.collectionName}`} items={collection} isLarge />
             </div>
        )}

      </div>
    </div>
  );
};

export default Details;

import { ANILIST_API_URL, ANILIST_TOKEN } from '../constants';
import { MediaItem } from '../types';

const graphQLRequest = async (query: string, variables: any = {}) => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  if (ANILIST_TOKEN) {
    headers['Authorization'] = `Bearer ${ANILIST_TOKEN}`;
  }

  const res = await fetch(ANILIST_API_URL, {
    method: 'POST',
    headers,
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    console.warn("AniList Request Warning", res.status);
    // Try to return json even on error to see messages, or throw
    try { return await res.json(); } catch(e) { throw new Error("AniList Failed"); }
  }
  return res.json();
};

const mapAniListToMedia = (item: any, type: 'anime' | 'manga'): MediaItem => ({
  id: item.id,
  anilistId: item.id,
  title: item.title.english || item.title.romaji,
  poster: item.coverImage.large,
  banner: item.bannerImage,
  description: item.description?.replace(/<[^>]*>?/gm, '') || '', // Strip HTML
  rating: item.averageScore ? item.averageScore / 10 : 0,
  releaseDate: item.startDate.year ? `${item.startDate.year}-${item.startDate.month || '01'}-${item.startDate.day || '01'}` : 'N/A',
  type,
  genres: item.genres || [],
  status: item.status,
  episodes: item.episodes || 0, // Total episodes
  chapters: item.chapters || 0, // Total chapters
});

const MEDIA_QUERY = `
  query ($id: Int, $search: String, $type: MediaType, $sort: [MediaSort]) {
    Page(page: 1, perPage: 20) {
      media(id: $id, search: $search, type: $type, sort: $sort) {
        id
        title {
          romaji
          english
        }
        coverImage {
          large
        }
        bannerImage
        description
        averageScore
        startDate {
          year
          month
          day
        }
        genres
        status
        episodes
        chapters
      }
    }
  }
`;

export const anilistService = {
  getTrending: async (type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      type: type.toUpperCase(),
      sort: ['TRENDING_DESC', 'POPULARITY_DESC']
    });
    return data.data?.Page?.media?.map((i: any) => mapAniListToMedia(i, type)) || [];
  },

  getPopular: async (type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      type: type.toUpperCase(),
      sort: ['POPULARITY_DESC']
    });
    return data.data?.Page?.media?.map((i: any) => mapAniListToMedia(i, type)) || [];
  },

  getDetails: async (id: number, type: 'anime' | 'manga'): Promise<MediaItem | null> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      id,
      type: type.toUpperCase()
    });
    const item = data.data?.Page?.media?.[0];
    return item ? mapAniListToMedia(item, type) : null;
  },

  search: async (query: string, type: 'anime' | 'manga'): Promise<MediaItem[]> => {
    const data = await graphQLRequest(MEDIA_QUERY, {
      search: query,
      type: type.toUpperCase(),
      sort: ['POPULARITY_DESC']
    });
    return data.data?.Page?.media?.map((i: any) => mapAniListToMedia(i, type)) || [];
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { tmdbService } from '../services/tmdb';
import { anilistService } from '../services/anilist';
import { MediaItem } from '../types';
import Row from '../components/Row';
import { Loader2, Play, Info, BookOpen } from 'lucide-react';

const Home: React.FC = () => {
  const [searchParams] = useSearchParams();
  const category = searchParams.get('cat'); // 'anime' | 'manga' | null

  const [loading, setLoading] = useState(true);
  const [heroMovie, setHeroMovie] = useState<MediaItem | null>(null);

  const [data, setData] = useState<{
    // Movies & TV
    trendingMovies: MediaItem[];
    trendingTv: MediaItem[];
    topRatedMovies: MediaItem[];
    popularTv: MediaItem[];
    actionMovies: MediaItem[];
    scifiMovies: MediaItem[];
    dramaMovies: MediaItem[];
    // Anime & Manga
    animeTrending: MediaItem[];
    animePopular: MediaItem[];
    mangaTrending: MediaItem[];
    mangaPopular: MediaItem[];
  }>({
    trendingMovies: [],
    trendingTv: [],
    topRatedMovies: [],
    popularTv: [],
    actionMovies: [],
    scifiMovies: [],
    dramaMovies: [],
    animeTrending: [],
    animePopular: [],
    mangaTrending: [],
    mangaPopular: []
  });

  const navigate = useNavigate();

  useEffect(() => {
    const fetchContent = async () => {
      setLoading(true);
      try {
        if (category === 'anime') {
            // --- FETCH ANIME ---
            const [trending, popular] = await Promise.all([
                anilistService.getTrending('anime'),
                anilistService.getPopular('anime')
            ]);

            setData(prev => ({ 
                ...prev, 
                animeTrending: trending, 
                animePopular: popular 
            }));

            if (trending.length > 0) {
                 setHeroMovie(trending[0]);
            }

        } else if (category === 'manga') {
            // --- FETCH MANGA ---
            const [trending, popular] = await Promise.all([
                anilistService.getTrending('manga'),
                anilistService.getPopular('manga')
            ]);

            setData(prev => ({ 
                ...prev, 
                mangaTrending: trending, 
                mangaPopular: popular 
            }));

            if (trending.length > 0) {
                 setHeroMovie(trending[0]);
            }

        } else {
            // --- FETCH MOVIES & TV (Default) ---
            const [
              trendingM, 
              trendingT, 
              topRatedM, 
              popularT,
              action,
              scifi,
              drama
            ] = await Promise.all([
              tmdbService.getTrending('movie'),
              tmdbService.getTrending('tv'),
              tmdbService.getTopRated('movie'),
              tmdbService.getPopular('tv'),
              tmdbService.getByGenre('movie', 28), // Action
              tmdbService.getByGenre('movie', 878), // Sci-Fi
              tmdbService.getByGenre('movie', 18),  // Drama
            ]);

            setData(prev => ({
              ...prev,
              trendingMovies: trendingM,
              trendingTv: trendingT,
              topRatedMovies: topRatedM,
              popularTv: popularT,
              actionMovies: action,
              scifiMovies: scifi,
              dramaMovies: drama
            }));

            // Pick a random movie from trending to be the hero
            if (trendingM.length > 0) {
              const random = trendingM[Math.floor(Math.random() * Math.min(10, trendingM.length))];
              setHeroMovie(random);
            }
        }
      } catch (e) {
        console.error("Home fetch error", e);
      } finally {
        setLoading(false);
      }
    };

    fetchContent();
  }, [category]); // Re-run whenever category changes

  if (loading) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-nexus-900">
        <Loader2 className="animate-spin text-nexus-accent h-12 w-12" />
      </div>
    );
  }

  // Helper to determine detail path prefix
  const getHeroPath = (item: MediaItem) => `/${item.type}/${item.id}`;
  const isReading = category === 'manga';

  return (
    <div className="pb-20 overflow-hidden">
      {/* Hero Billboard */}
      {heroMovie && (
        <div className="relative h-[85vh] w-full mb-8">
          <div className="absolute inset-0">
             <img 
               src={heroMovie.banner || heroMovie.poster} 
               alt={heroMovie.title} 
               className="w-full h-full object-cover"
             />
             <div className="absolute inset-0 bg-gradient-to-r from-nexus-900 via-nexus-900/40 to-transparent" />
             <div className="absolute inset-0 bg-gradient-to-t from-nexus-900 via-transparent to-transparent" />
          </div>

          <div className="absolute bottom-0 left-0 w-full p-6 md:p-12 mb-12">
            <h1 className="text-4xl md:text-6xl font-extrabold text-white mb-4 drop-shadow-lg max-w-2xl">
              {heroMovie.title}
            </h1>
            <p className="text-lg text-gray-200 max-w-xl line-clamp-3 mb-8 drop-shadow-md font-medium">
              {heroMovie.description}
            </p>
            <div className="flex gap-4">
              <button 
                onClick={() => navigate(getHeroPath(heroMovie))}
                className="bg-white text-black px-8 py-3 rounded-lg font-bold flex items-center gap-2 hover:bg-gray-200 transition"
              >
                {isReading ? <BookOpen fill="currentColor" size={20} /> : <Play fill="currentColor" size={20} />} 
                {isReading ? 'Read Now' : 'Play Now'}
              </button>
              <button 
                onClick={() => navigate(getHeroPath(heroMovie))}
                className="bg-gray-600/80 backdrop-blur text-white px-8 py-3 rounded-lg font-bold flex items-center gap-2 hover:bg-gray-600 transition"
              >
                <Info size={20} /> More Info
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Content Rows */}
      <div className="-mt-32 relative z-10 space-y-4">
        {category === 'anime' ? (
             <>
                <Row title="Trending Anime" items={data.animeTrending} isLarge />
                <Row title="All Time Popular" items={data.animePopular} />
             </>
        ) : category === 'manga' ? (
             <>
                <Row title="Trending Manga" items={data.mangaTrending} isLarge />
                <Row title="Most Popular to Read" items={data.mangaPopular} />
             </>
        ) : (
            // Default Movie/TV View
            <>
                <Row title="Trending Movies" items={data.trendingMovies} isLarge />
                <Row title="Trending TV Shows" items={data.trendingTv} />
                <Row title="Top Rated Movies" items={data.topRatedMovies} />
                <Row title="Popular TV Series" items={data.popularTv} />
                <Row title="Action Movies" items={data.actionMovies} />
                <Row title="Sci-Fi & Fantasy" items={data.scifiMovies} />
                <Row title="Dramatic Hits" items={data.dramaMovies} />
            </>
        )}
      </div>
    </div>
  );
};

export default Home;

